Given the stack (Kotlin backend, PostgreSQL, Redis, minimal dependencies philosophy), the simplest approach is a database-backed feature flag — no new service or dependency needed.

### Option: PostgreSQL table + Redis cache

```sql
-- Flyway migration: V__add_feature_flags.sql
CREATE TABLE feature_flags (
    name        TEXT PRIMARY KEY,
    enabled     BOOLEAN NOT NULL DEFAULT FALSE,
    percentage  INT,              -- for gradual rollout (0-100)
    updated_at  TIMESTAMPTZ NOT NULL DEFAULT now()
);

INSERT INTO feature_flags (name, enabled, percentage)
VALUES ('new_payment_flow', FALSE, 0);
```

```kotlin
// FeatureFlags.kt
class FeatureFlags(
    private val db: JdbcTemplate,
    private val redis: RedisTemplate<String, Boolean>
) {
    fun isEnabled(flag: String, userId: String? = null): Boolean {
        // Check Redis cache first
        val cacheKey = "ff:$flag"
        redis.opsForValue().get(cacheKey)?.let { return it }

        // Fall back to DB
        val row = db.queryForMap(
            "SELECT enabled, percentage FROM feature_flags WHERE name = ?", flag
        )
        val enabled = row["enabled"] as Boolean
        val percentage = row["percentage"] as Int?

        val result = when {
            !enabled -> false
            percentage != null -> userInRollout(userId, percentage)
            else -> true
        }

        redis.opsForValue().set(cacheKey, result, Duration.ofMinutes(1))
        return result
    }

    private fun userInRollout(userId: String?, percentage: Int): Boolean {
        if (userId == null) return false
        return (userId.hashCode().absoluteValue % 100) < percentage
    }
}
```

